func solve(nums []int64, target int64) int64 {
	// Helper structure to hold XOR sum and the maximum size achieving it
	type MapEntry struct {
		xor  int64
		size int64
	}

	// Generates a map where keys are XOR sums achievable by subsets of the array,
	// and values are the maximum size of a subset that achieves that XOR sum.
	generateXORSums := func(arr []int64) map[int64]int64 {
		// Map: XOR Sum -> Max Size
		results := make(map[int64]int64)

		// Initialize with the empty set: XOR sum 0, size 0
		results[0] = 0

		for _, num := range arr {
			// Store updates temporarily to avoid modifying the map while iterating over it
			updates := make([]MapEntry, 0)

			// Iterate over existing states (current XOR sum and size)
			for currentXor, currentSize := range results {
				// Create a new state by including 'num'
				newXor := currentXor ^ num
				newSize := currentSize + 1

				updates = append(updates, MapEntry{xor: newXor, size: newSize})
			}

			// Apply updates, prioritizing larger sizes for the same XOR sum
			for _, update := range updates {
				if size, exists := results[update.xor]; !exists || size < update.size {
					results[update.xor] = update.size
				}
			}
		}
		return results
	}

	N := int64(len(nums))
	if N == 0 {
		if target == 0 {
			return 0
		}
		return -1
	}

	// Split the array into two halves for Meet-in-the-Middle
	mid := int(N / 2)
	A := nums[:mid]
	B := nums[mid:]

	// Generate subset sums and max sizes for both halves
	mapA := generateXORSums(A)
	mapB := generateXORSums(B)

	maxKeptSize := int64(-1)

	// Combine results: Find XA ^ XB = target, maximizing sizeA + sizeB
	for xorA, sizeA := range mapA {
		requiredXorB := target ^ xorA

