			totalSize := sizeA + sizeB

			if totalSize > maxKeptSize {
				maxKeptSize = totalSize
			}
		}
	}

	if maxKeptSize == -1 {
		return -1
	} else {
		// Minimum removals = Total elements - Maximum kept elements
		return N - maxKeptSize
	}
}

